var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"추측건대, 고래는 나, 혹은 강한 카운터에 이끌린다.","JPN":"おそらく、クジラは私などの強いカウンターに引き寄せられる。","ENG":"My guess is that the whale is attracted to me or maybe strong Counters.","TWN":"根據推測，鯨魚會被我，或者強大的制裁者所吸引。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"하지만 첫 번째 조우에선 나를 몰아붙인 뒤 아샤를 삼키고 돌아갔어.","JPN":"しかし、初めて遭遇したときは私を跳ね除けて、アーシャを飲み込んでいなくなった。","ENG":"But in my first encounter with it, it cornered me, then swallowed Asha and went back.","TWN":"但是在第一次遇到時，它吞下阿莎之後就離開了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……굳이 나와 아샤를 분리하고, 삼킨 이유가 무엇이지?\xA0","JPN":"……わざわざ私とアーシャを引き離し、飲み込んだのはどうしてなんだ？\xA0","ENG":"...Why did it separate me from Asha and then take her?\xA0","TWN":"……為什麼只吞掉阿莎，刻意把我們分開呢？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WIND_VARUNA_GIRL_SHADOW","text":{"KOREA":"계속 기다려왔는데.","JPN":"ずっと待っていたのに。","ENG":"I've been waiting all this time for you.","TWN":"我一直在等你。 "},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_GIRL_SHADOW","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WIND_VARUNA_GIRL_SHADOW","text":{"KOREA":"왜 나를 기억하지 못하는 거야?","JPN":"どうして私を忘れちゃったの？","ENG":"But why can't you remember who I am?","TWN":"你為什麼不記得我？ "},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_GIRL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WIND_VARUNA_GIRL_SHADOW","text":{"KOREA":"계속해서 기다린다고 말했는데…….","JPN":"ずっとここで待っているって言ったのに……","ENG":"I told you that I'll keep on waiting...","TWN":"我明明說過我一直在等你……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_GIRL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WIND_VARUNA_GIRL_SHADOW","text":{"KOREA":"<color=#ff3636>근데 왜 당신은 찾아오지 않은 거야!!!!!</color>","JPN":"<color=#ff3636>どうしていつまでも来てくれなかったの！！！！</color>","ENG":"<color=#ff3636>BUT YOU NEVER CAME BACK FOR ME!!!!</color>","TWN":"<color=#ff3636>但為什麼你沒有來找我！！</color>"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_GIRL_SHADOW","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"……아디트야 님 잘못이 아니에요.","JPN":"……アーディティヤ様にはなんの非もありません。","ENG":"...It's not your fault, Miss Aditya.","TWN":"……這不是阿迪亞的錯。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"말도 안 되는 억지를 부려서…… 제가 그 죗값을 받는 거라고 생각해요…….","JPN":"私がわがままを言い過ぎたから……そのつけが回ってきたんです……","ENG":"I'm getting punished for... asking for those ridiculous requests...","TWN":"都怪我太強求……是我活該……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"꼭 기억을 되찾으셨으면 좋겠어요.","JPN":"必ず記憶を取り戻してくださいね。","ENG":"I hope you find your memories.","TWN":"希望你能找回記憶。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"짧은 시간이었지만, 전…….","JPN":"短い間でしたけど、私……","ENG":"We didn't know each other for that long, but...","TWN":"雖然我們認識的時間很短，但我……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"내가 힘을 제어하지 못해서 아샤가 다친 거야…….","JPN":"私が力の制御ができないせいで、アーシャが怪我をしたんだ……","ENG":"Asha got hurt because I couldn't control my power.","TWN":"因為無法控制我的力量，才會害阿莎受傷……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그 여파로 결국 그녀가…….","JPN":"それによって、彼女は……","ENG":"And because of that, she...","TWN":"所以她才會……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"모든 게 내 잘못이야…… 어떻게든 이 일을 마무리 지어야 해.","JPN":"すべて私のせいだ……なんとしてでも、この件にはけりをつける。","ENG":"It's all my fault... So I must finish it.","TWN":"都是我的錯……無論如何我必須結束這件事。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……나침반의 바늘은 여전히 방향을 잡지 못하고 있어.","JPN":"……羅針盤の針は、相変わらず方向が安定しないままだ。","ENG":"...The compass still can't point to a direction.","TWN":"……指南針的指針依然無法確定方向。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"역시 아샤는…… ","JPN":"やっぱりアーシャは…… ","ENG":"Did Asha...","TWN":"難道阿莎她……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"분명 너는 내 손으로 직접 처리했는데. 역시 도플갱어 타입이었나?","JPN":"お前は確か私が倒したはず。やはりドッペルシャドウだったのか？","ENG":"I thought I killed you already. So you are a Doppelganger-type, just as I thought.","TWN":"我明明已經親手把你處理掉，果然是二重身嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"이번 도플갱어는 조금 과묵한 타입이군.","JPN":"今回のドッペルゲンガーは口を開かないのか。","ENG":"This one doesn't seem like a talkative one.","TWN":"看來這次的二重身有些不愛說話。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"이젠 질질 끌려다니는 건 질색이야. 단번에 뚫고 가겠다.","JPN":"もう振り回されるのは十分だ。一気にかたを付けてやる。","ENG":"I don't want to be dragged around like this anymore. I'll make a breakthrough at once.","TWN":"我討厭拖拖拉拉的，放馬過來吧。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};